//! Verus companion file generator for `elicitation generate verus`.
//!
//! Takes a `VsmDescriptor` (produced by the source scanner) and emits a Rust
//! source file containing Verus `assume_specification` contracts that replace
//! what `VerifiedStateMachine::vsm_verus_proof()` produces at build time.
//!
//! The generated file follows the pattern in `elicit_proofs/src/verus/generated/`:
//! 1. `#![allow(unexpected_cfgs)]` — suppress unknown cfg key warnings
//! 2. `#[cfg(verus)] use` imports (fixed prelude + type-resolved)
//! 3. `#[cfg(verus)] verus! { pub open spec fn inv(state) -> bool { <body> } }`
//! 4. `verus! { pub fn verify_*_prop_contract() }` marker
//! 5. Per-transition: `verus! { pub assume_specification [fn_name](...) requires ..., ensures ...; }`

use std::collections::BTreeSet;
use std::path::Path;

use crate::cli::generate::{
    TypeResolver,
    find_crate_name,
    scanner::{ArgKind, TransitionFn, VsmDescriptor},
};

// ─── Public API ───────────────────────────────────────────────────────────────

/// Generate the full Verus companion file content for `vsm`.
///
/// `crate_root` is used to discover the crate name via `Cargo.toml`.  The VSM
/// source file is parsed with [`TypeResolver`] to produce precise `use` imports
/// rather than glob wildcards.
///
/// Returns `Err` with an actionable message when a named invariant is present
/// but `verus_inv_body` could not be resolved.
#[tracing::instrument(skip(vsm, crate_root), fields(machine = %vsm.machine))]
pub fn generate_verus_file(
    vsm: &VsmDescriptor,
    crate_root: impl AsRef<Path>,
) -> Result<String, String> {
    let machine = &vsm.machine;
    let state_ty = machine.replace("Machine", "State");
    let crate_name = find_crate_name(crate_root.as_ref());

    // Resolve invariant — error only when an invariant exists without a body.
    let inv_parts: Option<(&str, &str, &str)> = match &vsm.invariant {
        Some(p) => {
            let fn_name = p
                .verus_fn
                .as_deref()
                .unwrap_or_else(|| p.name.as_str());
            let body = p.verus_inv_body.as_deref().ok_or_else(|| {
                let hint_fn = p.verus_fn.as_deref().unwrap_or("verus_invariant_fn");
                format!(
                    "cannot generate Verus companion for {machine}: \
                     invariant body for `{hint_fn}` not found\n  \
                     hint: add `verus_inv_body = \"...\"` to #[prop(...)] on `{name}`,\n  \
                        or define `pub fn {hint_fn}(state: &{state_ty}) -> bool {{ ... }}`\n  \
                           in a file under the scan root (without #[cfg(verus)] gate)",
                    name = p.name,
                )
            })?;
            Some((fn_name, p.name.as_str(), body))
        }
        None => None,
    };

    // ── Collect the bare type names this file will reference ─────────────────
    let mut needed: BTreeSet<String> = BTreeSet::new();
    TypeResolver::collect_type(&state_ty, &mut needed);
    if let Some((_, consistent_ty, _)) = inv_parts {
        TypeResolver::collect_type(consistent_ty, &mut needed);
    }
    for tfn in &vsm.transition_fns {
        for arg in &tfn.args {
            match &arg.kind {
                ArgKind::Proof { inner } => TypeResolver::collect_type(inner, &mut needed),
                _ => TypeResolver::collect_type(&arg.ty, &mut needed),
            }
        }
    }

    let resolver = TypeResolver::build(&vsm.source_file, &crate_name);
    let resolved_imports = resolver.grouped_imports(&needed);

    let mut lines: Vec<String> = Vec::new();

    // ── Header ──────────────────────────────────────────────────────────────
    lines.push("// AUTO-GENERATED by `elicitation generate verus` — DO NOT EDIT".to_string());
    lines.push("//".to_string());
    lines.push(format!("// Verus companion contracts for {machine}."));
    lines.push("// Regenerate: elicitation generate verus --crate-path <root>".to_string());
    lines.push("//".to_string());
    lines.push(
        "// All items are gated with #[cfg(verus)]; invisible to normal Rust builds.".to_string(),
    );
    lines.push("// The `verus` cfg key is set by the Verus toolchain, not by cargo.".to_string());
    lines.push("#![allow(unexpected_cfgs)]".to_string());
    lines.push(String::new());

    // ── Imports ─────────────────────────────────────────────────────────────
    // Fixed: Verus stdlib prelude, macro re-export, and elicitation types.
    for import in &[
        "::vstd::prelude::*".to_string(),
        "::verus_builtin_macros::verus".to_string(),
        "elicitation::Established".to_string(),
    ] {
        lines.push("#[cfg(verus)]".to_string());
        lines.push(format!("use {import};"));
    }
    // Type-resolved: precise imports for every user-crate type referenced.
    for import in &resolved_imports {
        lines.push("#[cfg(verus)]".to_string());
        lines.push(format!("use {import};"));
    }
    lines.push(String::new());

    // ── Invariant spec fn ────────────────────────────────────────────────────
    if let Some((inv_fn, consistent_ty, inv_body)) = inv_parts {
        lines.push("#[cfg(verus)]".to_string());
        lines.push(format!(
            "verus! {{ pub open spec fn {inv_fn}(state: &{state_ty}) -> bool {{ {inv_body} }} }}"
        ));

        // ── Marker proof ─────────────────────────────────────────────────────
        lines.push(format!(
            "verus! {{ pub fn verify_{consistent_lower}_prop_contract() \
             -> (result: bool) ensures result == true, {{ true }} }}",
            consistent_lower = to_snake(consistent_ty),
        ));

        // ── Per-transition assume_specifications ─────────────────────────────
        for name in &vsm.transitions {
            let tf = vsm.transition_fns.iter().find(|tf| &tf.name == name);
            lines.push(emit_assume_specification(
                name,
                &state_ty,
                consistent_ty,
                inv_fn,
                tf,
            ));
        }
    }

    Ok(lines.join("\n") + "\n")
}

// ─── Emitters ────────────────────────────────────────────────────────────────

/// Emit one `verus! { pub assume_specification [...] ... ; }` block.
fn emit_assume_specification(
    fn_name: &str,
    state_ty: &str,
    consistent_ty: &str,
    inv_fn: &str,
    tf: Option<&TransitionFn>,
) -> String {
    let args_str = match tf {
        Some(tf) => emit_args(tf),
        None => format!("(_state: {state_ty}, proof: Established<{consistent_ty}>,)"),
    };

    let state_param = match tf {
        Some(tf) => tf.state_arg().map(|a| a.name.as_str()).unwrap_or("_state"),
        None => "_state",
    };
    let state_ref = state_param.trim_start_matches('_');
    let state_ref = if state_ref.is_empty() { "state" } else { state_ref };

    format!(
        "verus! {{ pub assume_specification [{fn_name}] \
         {args_str} \
         -> (r: ({state_ty}, Established<{consistent_ty}>,)) \
         requires {inv_fn}(&{state_ref}), \
         ensures {inv_fn}(&r.0), \
         ; }}"
    )
}

/// Emit the argument list as a Verus-style parenthesised tuple string.
fn emit_args(tf: &TransitionFn) -> String {
    let mut parts: Vec<String> = Vec::new();
    for arg in &tf.args {
        let ty = match &arg.kind {
            ArgKind::Proof { inner } => format!("Established<{inner}>"),
            _ => arg.ty.clone(),
        };
        parts.push(format!("{}: {ty},", arg.name));
    }
    format!("({})", parts.join(" "))
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/// Convert PascalCase to snake_case.
fn to_snake(s: &str) -> String {
    let mut out = String::new();
    for (i, ch) in s.chars().enumerate() {
        if ch.is_uppercase() && i > 0 {
            out.push('_');
        }
        out.push(ch.to_ascii_lowercase());
    }
    out
}
